from dataclasses import dataclass
from typing import Tuple

# %% ../../nbs/euclid/constants.ipynb 3
# camera constants


@dataclass(frozen=True)
class Camera:
    name: str
    chips: Tuple[str, ...]
    filters: Tuple[str, ...]
    pix_scale: float
    bad_pix_bits: Tuple[int, ...] = None
    chip_subdivisions: Tuple[str, ...] = None

    @property
    def extnames(self):
        if self.chip_subdivisions is None:
            return self.chips
        else:
            return tuple(
                f"{chip}.{sub}" for chip in self.chips for sub in self.chip_subdivisions
            )


VIS = Camera(
    name="VIS",
    chips=tuple(f"{x}-{y}" for x in range(1, 7) for y in range(1, 7)),
    chip_subdivisions=("E", "F", "G", "H"),
    filters=("I",),
    bad_pix_bits=(0,),  # 0 is the common flag for all invlid pixels
    pix_scale=0.1,
)
NISP = Camera(
    name="NISP",
    chips=tuple(f"DET{x}{y}" for x in range(1, 5) for y in range(1, 5)),
    filters=("Y", "J", "H"),
    bad_pix_bits=(0,),  # 0 is the common flag for all invlid pixels
    pix_scale=0.3,
)

